+fn optional_bool(input: &serde_json::Value, field: &str, default: bool) -> FcpResult<bool> {
+    match input.get(field) {
+        None | Some(serde_json::Value::Null) => Ok(default),
+        Some(value) => value.as_bool().ok_or_else(|| FcpError::InvalidRequest {
