+        stdout.flush()?;
+    }
+
+    Ok(())
+}
+
+fn encode<T: serde::Serialize>(value: &T) -> FcpResult<serde_json::Value> {
+    serde_json::to_value(value).map_err(|error| FcpError::Internal {
+        message: format!("Failed to serialize response: {error}"),
+    })
+}
+
+#[allow(clippy::too_many_lines)]
+async fn handle_message(connector: &mut MatrixConnector, message: &str) -> serde_json::Value {
+    let request: serde_json::Value = match serde_json::from_str(message) {
+        Ok(value) => value,
+        Err(error) => {
+            return serde_json::json!({
+                "jsonrpc": "2.0",
+                "error": {
+                    "code": "FCP-1001",
+                    "message": format!("Invalid JSON: {error}")
+                }
+            });
+        }
+    };
+
+    let method = request
+        .get("method")
+        .and_then(|value| value.as_str())
+        .unwrap_or("");
+    let id = request.get("id").cloned();
+    let params = request
+        .get("params")
+        .cloned()
+        .unwrap_or_else(|| serde_json::json!({}));
+
+    let result: FcpResult<serde_json::Value> = async {
+        match method {
+            "configure" => {
+                connector.configure(params).await?;
+                Ok(serde_json::json!({ "status": "configured" }))
+            }
+            "handshake" => {
+                let request: HandshakeRequest =
+                    serde_json::from_value(params).map_err(|error| FcpError::InvalidRequest {
+                        code: 1003,
+                        message: format!("Invalid handshake request: {error}"),
+                    })?;
+                encode(&connector.handshake(request).await?)
+            }
+            "health" => encode(&connector.health().await),
+            "doctor" => encode(&connector.doctor()),
+            "self_check" => encode(&connector.self_check().await?),
+            "introspect" => encode(&connector.introspect()),
+            "invoke" => {
+                let request: InvokeRequest =
+                    serde_json::from_value(params).map_err(|error| FcpError::InvalidRequest {
+                        code: 1003,
+                        message: format!("Invalid invoke request: {error}"),
+                    })?;
+                encode(&connector.invoke(request).await?)
+            }
+            "simulate" => {
+                let request: SimulateRequest =
+                    serde_json::from_value(params).map_err(|error| FcpError::InvalidRequest {
+                        code: 1003,
+                        message: format!("Invalid simulate request: {error}"),
+                    })?;
+                encode(&connector.simulate(request).await?)
+            }
+            "subscribe" => {
+                let request: SubscribeRequest =
+                    serde_json::from_value(params).map_err(|error| FcpError::InvalidRequest {
+                        code: 1003,
+                        message: format!("Invalid subscribe request: {error}"),
+                    })?;
+                encode(&connector.subscribe(request).await?)
+            }
+            "unsubscribe" => {
+                let request: UnsubscribeRequest =
+                    serde_json::from_value(params).map_err(|error| FcpError::InvalidRequest {
+                        code: 1003,
+                        message: format!("Invalid unsubscribe request: {error}"),
+                    })?;
+                connector.unsubscribe(request).await?;
+                Ok(serde_json::json!({ "status": "unsubscribed" }))
+            }
+            "shutdown" => {
+                let request: ShutdownRequest =
+                    serde_json::from_value(params).map_err(|error| FcpError::InvalidRequest {
+                        code: 1003,
+                        message: format!("Invalid shutdown request: {error}"),
+                    })?;
+                connector.shutdown(request).await?;
+                Ok(serde_json::json!({ "status": "shutdown_accepted" }))
+            }
+            _ => Err(FcpError::InvalidRequest {
+                code: 1002,
+                message: format!("Unknown method: {method}"),
+            }),
+        }
+    }
+    .await;
+
+    match result {
+        Ok(value) => {
+            let mut response = serde_json::json!({
+                "jsonrpc": "2.0",
+                "result": value
+            });
+            if let Some(id) = id {
+                response["id"] = id;
+            }
+            response
+        }
+        Err(error) => {
+            let err_response = error.to_response();
+            let mut response = serde_json::json!({
+                "jsonrpc": "2.0",
+                "error": err_response
+            });
+            if let Some(id) = id {
+                response["id"] = id;
+            }
+            response
+        }
+    }
+}
+
+#[cfg(test)]
+mod tests {
+    use super::*;
+
+    #[fcp_async_core::runtime::test]
+    async fn invalid_json_is_reported() {
+        let mut connector = MatrixConnector::new();
+        let response = handle_message(&mut connector, "{not json").await;
+        assert_eq!(response["jsonrpc"], "2.0");
+        assert_eq!(response["error"]["code"], "FCP-1001");
+    }
 }

